import React, { useState, useEffect } from 'react';
import {
  Box,
  Card,
  CardContent,
  Grid,
  Button,
  Typography,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Chip,
  Stack,
  Alert,
  Snackbar,
  LinearProgress
} from '@mui/material';
import {
  Add as AddIcon,
  Edit as EditIcon,
  Delete as DeleteIcon,
  Refresh as RefreshIcon,
  Speed as SpeedIcon
} from '@mui/icons-material';
import { 
  getNodes, 
  getNodeStatus, 
  createNode,
  updateNode, 
  deleteNode 
} from '../services/api';

const Nodes = () => {
  const [nodes, setNodes] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(false);
  const [openDialog, setOpenDialog] = useState(false);
  const [selectedNode, setSelectedNode] = useState(null);
  const [editNode, setEditNode] = useState({
    name: '',
    type: 'select',
    region: '',
    subscription: '',
    excludes: [],
    includes: []
  });

  useEffect(() => {
    fetchNodes();
  }, []);

  const fetchNodes = async () => {
    try {
      setLoading(true);
      const data = await getNodes();
      setNodes(data);
    } catch (err) {
      setError('Failed to load nodes');
    } finally {
      setLoading(false);
    }
  };

  const handleOpenDialog = (node = null) => {
    if (node) {
      setSelectedNode(node);
      setEditNode(node);
    } else {
      setSelectedNode(null);
      setEditNode({
        name: '',
        type: 'select',
        region: '',
        subscription: '',
        excludes: [],
        includes: []
      });
    }
    setOpenDialog(true);
  };

  const handleCloseDialog = () => {
    setOpenDialog(false);
    setSelectedNode(null);
    setEditNode({
      name: '',
      type: 'select',
      region: '',
      subscription: '',
      excludes: [],
      includes: []
    });
  };

  const handleSave = async () => {
    try {
      setLoading(true);
      if (selectedNode) {
        await updateNode(selectedNode.id, editNode);
      }
      await fetchNodes();
      setSuccess(true);
      handleCloseDialog();
    } catch (err) {
      setError('Failed to save node');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    try {
      setLoading(true);
      await deleteNode(id);
      await fetchNodes();
      setSuccess(true);
    } catch (err) {
      setError('Failed to delete node');
    } finally {
      setLoading(false);
    }
  };

  const handleRefresh = async (id) => {
    try {
      setLoading(true);
      await getNodeStatus(id);
      await fetchNodes();
      setSuccess(true);
    } catch (err) {
      setError('Failed to refresh node status');
    } finally {
      setLoading(false);
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'running':
        return 'success';
      case 'stopped':
        return 'error';
      case 'warning':
        return 'warning';
      default:
        return 'default';
    }
  };

  return (
    <Box>
      <Snackbar 
        open={success} 
        autoHideDuration={3000} 
        onClose={() => setSuccess(false)}
      >
        <Alert severity="success">Operation completed successfully</Alert>
      </Snackbar>

      <Snackbar 
        open={!!error} 
        autoHideDuration={3000} 
        onClose={() => setError(null)}
      >
        <Alert severity="error">{error}</Alert>
      </Snackbar>

      <Box sx={{ mb: 2, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <Typography variant="h5">节点管理</Typography>
        <Button
          variant="outlined"
          size="small"
          startIcon={<AddIcon />}
          onClick={() => handleOpenDialog()}
        >
          添加节点
        </Button>
      </Box>

      {loading && <LinearProgress sx={{ mb: 2 }} />}

      <Grid container spacing={2}>
        {nodes.map((node) => (
          <Grid item xs={12} sm={6} lg={4} key={node.id}>
            <Card>
              <CardContent>
                <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 1.5 }}>
                  <Typography variant="h6">{node.name}</Typography>
                  <Stack direction="row" spacing={0.5}>
                    <IconButton size="small" onClick={() => handleRefresh(node.id)}>
                      <RefreshIcon fontSize="small" />
                    </IconButton>
                    <IconButton size="small" onClick={() => handleOpenDialog(node)}>
                      <EditIcon fontSize="small" />
                    </IconButton>
                    <IconButton size="small" onClick={() => handleDelete(node.id)}>
                      <DeleteIcon fontSize="small" />
                    </IconButton>
                  </Stack>
                </Box>
                <Stack direction="row" spacing={1} sx={{ mb: 1.5 }}>
                  <Chip 
                    label={node.type} 
                    color="primary" 
                    size="small" 
                  />
                  <Chip 
                    label={node.region} 
                    color="secondary" 
                    size="small" 
                  />
                  <Chip 
                    label={node.status} 
                    color={getStatusColor(node.status)} 
                    size="small" 
                  />
                </Stack>
                {node.speed && (
                  <Box sx={{ display: 'flex', alignItems: 'center' }}>
                    <SpeedIcon sx={{ mr: 0.5, fontSize: 16 }} color="action" />
                    <Typography variant="body2" color="text.secondary">
                      {node.speed} Mbps
                    </Typography>
                  </Box>
                )}
              </CardContent>
            </Card>
          </Grid>
        ))}
      </Grid>

      <Dialog open={openDialog} onClose={handleCloseDialog} maxWidth="sm" fullWidth>
        <DialogTitle>
          {selectedNode ? '编辑节点' : '添加节点'}
        </DialogTitle>
        <DialogContent>
          <Box sx={{ pt: 2 }}>
            <Grid container spacing={2}>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="节点名称"
                  value={editNode.name}
                  onChange={(e) => setEditNode({ ...editNode, name: e.target.value })}
                  size="small"
                />
              </Grid>
              <Grid item xs={12}>
                <FormControl fullWidth size="small">
                  <InputLabel>节点类型</InputLabel>
                  <Select
                    value={editNode.type}
                    label="节点类型"
                    onChange={(e) => setEditNode({ ...editNode, type: e.target.value })}
                  >
                    <MenuItem value="select">Select</MenuItem>
                    <MenuItem value="urltest">URLTest</MenuItem>
                    <MenuItem value="fallback">Fallback</MenuItem>
                  </Select>
                </FormControl>
              </Grid>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="地区"
                  value={editNode.region}
                  onChange={(e) => setEditNode({ ...editNode, region: e.target.value })}
                  size="small"
                />
              </Grid>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="订阅"
                  value={editNode.subscription}
                  onChange={(e) => setEditNode({ ...editNode, subscription: e.target.value })}
                  size="small"
                />
              </Grid>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="排除规则"
                  value={editNode.excludes.join(', ')}
                  onChange={(e) => setEditNode({ ...editNode, excludes: e.target.value.split(',').map(s => s.trim()) })}
                  helperText="多个规则用逗号分隔"
                  size="small"
                />
              </Grid>
              <Grid item xs={12}>
                <TextField
                  fullWidth
                  label="包含规则"
                  value={editNode.includes.join(', ')}
                  onChange={(e) => setEditNode({ ...editNode, includes: e.target.value.split(',').map(s => s.trim()) })}
                  helperText="多个规则用逗号分隔"
                  size="small"
                />
              </Grid>
            </Grid>
          </Box>
        </DialogContent>
        <DialogActions>
          <Button onClick={handleCloseDialog} size="small">取消</Button>
          <Button 
            variant="contained" 
            onClick={handleSave}
            disabled={loading}
            size="small"
          >
            保存
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

export default Nodes;
